sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// KT - REQUEST TYPE

//----------------------------------------------------------------------------------------------------------
// Request Clarification
//----------------------------------------------------------------------------------------------------------
if(current.u_request_type == "Clarification"){

	var errorMessage = 'Request ' + current.number + ' did not meet the conditions to submit a Request Clarification. Please validate that you are either the Assigned Member OR Reviewer OR Primary Assignee Task Manager (OUTA) OR Task Administrator (GTA), and that you are not all three the Task Owner, Assigned Member and Reviewer';

	if( current.parent != "" &&
		current.parent.u_clarification_requested == false) {

		var taskWorkNotes = 'Clarification Request has been created by ' + gs.getUserDisplayName() + ' with the following comments: ' + current.u_request_comments;

		//KT: Update Task table
		var parentId = current.parent.toString();
		var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
		if (grTask.get(parentId)){

			var allow = new uiConditionCheck().RequestClarification(grTask);

			if (allow) {
				grTask.u_clarification_requested = true;
				grTask.work_notes = taskWorkNotes;
				grTask.update();

				//KT: Update Request table
				var todaysDate = new GlideDateTime();
				current.u_requested_by = gs.getUserID();
				current.u_requested = todaysDate;
				current.update();

				gs.addInfoMessage(taskWorkNotes);

				//-------
				//get the person who is going to receive
				var recipient = grTask.getValue('u_task_requester').toString();
				var requestedby = gs.getUserDisplayName();//current.getValue('u_requested_by').toString();

				gs.eventQueue('x_153465_discovert.NotifClarificationReq', grTask, requestedby, recipient);
				//-------
			}
			else gs.addErrorMessage(errorMessage);
		}
	} else gs.addErrorMessage(errorMessage);
}

//----------------------------------------------------------------------------------------------------------
// Request Extension
//----------------------------------------------------------------------------------------------------------
if(current.u_request_type == "Extension"){

	var errorMessage = 'Request ' + current.number + ' did not meet the conditions to submit a Request Extension';

	if( current.parent != "" &&
		current.parent.state == 13 &&
	current.parent.extension_requested == false &&
	current.parent.assigned_to == gs.getUserID()) {

		var taskWorkNotes = 'Extension Request has been created by ' + gs.getUserDisplayName() + ' (Asignee) with the requested suspense date: ' + current.u_requested_suspense_date + ' and the following comments: ' + current.u_request_comments;

		//KT: Update Task table
		var parentId = current.parent.toString();
		var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
		if (grTask.get(parentId)){

			var allow = new uiConditionCheck().RequestExtension(grTask);

			if (allow) {
				grTask.extended_suspense_date = current.u_requested_suspense_date;
				grTask.extension_approval = '';
				grTask.extension_requested = true;
				grTask.work_notes = taskWorkNotes;

				grTask.update();

				//KT: Update Request table
				var todaysDate = new GlideDateTime();
				current.u_requested_by = gs.getUserID();
				current.u_requested = todaysDate;
				current.update();

				gs.addInfoMessage(taskWorkNotes);
				// STRY0073582
			} else gs.addErrorMessage(errorMessage);
		}
	} else gs.addErrorMessage(errorMessage);
}


//----------------------------------------------------------------------------------------------------------
// Request Reassignment
//----------------------------------------------------------------------------------------------------------
if(current.u_request_type == "Reassignment") {

	var errorMessage = 'Request ' + current.number + ' did not meet the conditions to submit a Request Reassignment';

	if (current.parent != "" &&
		current.parent.state == 13 &&
	current.parent.reassignment_requested == false &&
	current.parent.assigned_to == gs.getUserID()) {


		var taskWorkNotes = 'Reassignment Request has been created by ' + gs.getUserDisplayName() + ' (Asignee) with the following comments: ' + current.u_request_comments;

		//KT: Update Task table
		var parentId = current.parent.toString();
		var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
		if (grTask.get(parentId)){

			var allow = new uiConditionCheck().RequestReassignment(grTask);

			if (allow) {
				grTask.reassignment_approval = '';
				grTask.reassignment_requested = 'true';
				grTask.work_notes = taskWorkNotes;
				grTask.update();

				//KT: Update Request table
				var todaysDate = new GlideDateTime();
				current.u_requested_by = gs.getUserID();
				current.u_requested = todaysDate;
				current.update();

				gs.addInfoMessage(taskWorkNotes);

			} else gs.addErrorMessage(errorMessage);
		}
	} else gs.addErrorMessage(errorMessage);
}
